mapper.select:
select id, table_name, field_key, field_label, field_type, field_options, is_required, sort_order, status, del_flag, create_by, create_time, update_by, update_time, remark from proj_field_def where del_flag = '0'
and table_name = #{tableName}
and field_key like concat('%', #{fieldKey}, '%')
and field_label like concat('%', #{fieldLabel}, '%')
and status = #{status}
order by table_name, sort_order

mapper.insert:
insert into proj_field_def (
    table_name, field_key, field_label, field_type, field_options,
    is_required, sort_order, status, del_flag,
    create_by, create_time, remark
) values (
    #{tableName}, #{fieldKey}, #{fieldLabel}, #{fieldType}, #{fieldOptions},
    #{isRequired}, #{sortOrder}, #{status}, '0',
    #{createBy}, now(), #{remark}
)

mapper.update:
update proj_field_def
table_name = #{tableName}, field_key = #{fieldKey}, field_label = #{fieldLabel}, field_type = #{fieldType}, field_options = #{fieldOptions}, is_required = #{isRequired}, sort_order = #{sortOrder}, status = #{status}, remark = #{remark}, update_by = #{updateBy}, update_time = now()
where id = #{id}
